    }
}

/* Test driver */
public class Main {
    public static void main(String[] args) {
        Game g = new Game(new Player("A", Color.WHITE), new Player("B", Color.BLACK));
        g.makeMove(new Position(6,4), new Position(4,4));
        boolean undone = g.undoLastMove();
        if (undone && g.getCurrentTurn() == Color.WHITE && g.getBoard().getPieceAt(new Position(6,4)) instanceof Pawn) System.out.println("OK_UNDO");
        else System.out.println("FAIL_UNDO");
    }
}
